import os
import json
import re
import glob
from collections import defaultdict

def parse_supplier_receipt(filepath):
    items = []
    if filepath.endswith('.json'):
        with open(filepath) as f:
            data = json.load(f)
        for item in data.get('items', []):
            items.append((item['prod_id'], item['delivered_qty']))
    elif filepath.endswith('.csv'):
        with open(filepath) as f:
            lines = f.read().strip().split('\n')
        for line in lines[1:]:
            parts = line.strip().split(';')
            if len(parts) == 2:
                items.append((parts[0], int(parts[1])))
    elif 'text-template' in filepath:
        with open(filepath) as f:
            for line in f:
                m = re.search(r'delivered (\d+) units of product (P_\d+)', line)
                if m:
                    items.append((m.group(2), int(m.group(1))))
    elif 'key-value' in filepath:
        with open(filepath) as f:
            for line in f:
                m = re.search(r'PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)', line)
                if m:
                    items.append((m.group(1), int(m.group(2))))
    return items

# Day 1: compute total supply vs total store orders vs total delivered
print("=== DAY 1 SUPPLY/DEMAND ANALYSIS ===")

# Total supplier deliveries on day 1
day1_supply = defaultdict(int)
for f in glob.glob('/app/raw_supplier_receipts/day_001_PR_*'):
    items = parse_supplier_receipt(f)
    for prod, qty in items:
        day1_supply[prod] += qty

# Total store orders on day 1
day1_orders = defaultdict(int)
for f in glob.glob('/app/raw_orders/day_001_S_*'):
    items_list = []
    if f.endswith('.json'):
        with open(f) as fp:
            data = json.load(fp)
        for item in data.get('items', []):
            items_list.append((item['prod_id'], item['qty']))
    elif f.endswith('.csv'):
        with open(f) as fp:
            lines = fp.read().strip().split('\n')
        for line in lines[1:]:
            parts = line.strip().split(';')
            if len(parts) == 2:
                items_list.append((parts[0], int(parts[1])))
    elif 'text-template' in f:
        with open(f) as fp:
            for line in fp:
                m = re.search(r'deliver (\d+) units of product (P_\d+)', line)
                if m:
                    items_list.append((m.group(2), int(m.group(1))))
    elif 'key-value' in f:
        with open(f) as fp:
            for line in fp:
                m = re.search(r'ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)', line)
                if m:
                    items_list.append((m.group(1), int(m.group(2))))
    for prod, qty in items_list:
        day1_orders[prod] += qty

# Total delivered to all stores on day 1
total_delivered = 0
for f in glob.glob('/app/raw_wholesaler_store_receipts/day_001_S_*_receipt.txt'):
    with open(f) as fp:
        content = fp.read()
    total = int(re.search(r'TOTAL_DELIVERED_UNITS: (\d+)', content).group(1))
    total_delivered += total

total_supply = sum(day1_supply.values())
total_orders = sum(day1_orders.values())

print(f"Total supply from all suppliers on day 1: {total_supply}")
print(f"Total orders from all stores on day 1: {total_orders}")
print(f"Total delivered to all stores on day 1: {total_delivered}")
print()
print("Per-product supply vs orders vs ratio:")
all_prods = sorted(set(list(day1_supply.keys()) + list(day1_orders.keys())))
for p in all_prods:
    s = day1_supply[p]
    o = day1_orders[p]
    ratio = s/o if o > 0 else 'inf'
    if isinstance(ratio, float):
        ratio = f"{ratio:.2f}"
    print(f"  {p}: supply={s}, orders={o}, ratio={ratio}")
